CREATE TABLE offers (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,code VARCHAR(100) NOT NULL UNIQUE,title VARCHAR(255) NOT NULL,description VARCHAR(2000),discount_type VARCHAR(32) NOT NULL,discount_value DECIMAL(19,2) NOT NULL,min_order_amount DECIMAL(19,2) NOT NULL,max_discount_amount DECIMAL(19,2),usage_limit INTEGER,used_count INTEGER NOT NULL,target_role VARCHAR(32),active BOOLEAN NOT NULL,starts_at TIMESTAMP NOT NULL,ends_at TIMESTAMP NOT NULL,created_at TIMESTAMP,updated_at TIMESTAMP);
CREATE TABLE marketing_campaigns (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,name VARCHAR(255) NOT NULL,description VARCHAR(2000),campaign_type VARCHAR(32) NOT NULL,target_segment VARCHAR(100) NOT NULL,status VARCHAR(32) NOT NULL,starts_at TIMESTAMP,ends_at TIMESTAMP,created_at TIMESTAMP,updated_at TIMESTAMP);
CREATE TABLE marketing_banners (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,title VARCHAR(255) NOT NULL,subtitle VARCHAR(500),image_url VARCHAR(1000),deeplink VARCHAR(1000),placement VARCHAR(32) NOT NULL,active BOOLEAN NOT NULL,starts_at TIMESTAMP,ends_at TIMESTAMP,created_at TIMESTAMP,updated_at TIMESTAMP);
CREATE TABLE marketing_notifications (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,title VARCHAR(255) NOT NULL,message VARCHAR(2000) NOT NULL,target_segment VARCHAR(100) NOT NULL,sent_by_admin_id BIGINT NOT NULL,status VARCHAR(32) NOT NULL,created_at TIMESTAMP,sent_at TIMESTAMP);
